  1→/**
  2→ * OAuth RAR+DPoP Acceptance Test Kit
  3→ *
  4→ * Extends the shared acceptance-test-kit with OAuth-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/auth/intents              (intent submission with DPoP binding)
  9→ *   POST /api/auth/token                (Custom AS token endpoint)
 10→ *   POST /api/auth/bridge/exchange      (session-to-token Bridge)
 11→ *   GET  /api/auth/brain/.well-known/jwks (AS public keys)
 12→ *   All /api/mcp/* routes               (DPoP-protected Brain endpoints)
 13→ */
 14→import { RecordId, type Surreal } from "surrealdb";
 15→import * as jose from "jose";
 16→import {
 17→  setupAcceptanceSuite,
 18→  createTestUser,
 19→  fetchRaw,
 20→  type AcceptanceTestRuntime,
 21→  type TestUser as BaseTestUser,
 22→} from "../acceptance-test-kit";
 23→
 24→// Re-export shared kit essentials
 25→export {
 26→  setupAcceptanceSuite,
 27→  createTestUser,
 28→  fetchRaw,
 29→  type AcceptanceTestRuntime,
 30→  type TestUser as BaseTestUser,
 31→} from "../acceptance-test-kit";
 32→
 33→// ---------------------------------------------------------------------------
 34→// Types -- Business Language
 35→// ---------------------------------------------------------------------------
 36→
 37→export type DPoPKeyPair = {
 38→  privateKey: CryptoKey;
 39→  publicKey: CryptoKey;
 40→  publicJwk: JsonWebKey;
 41→  thumbprint: string;
 42→};
 43→
 44→export type BrainAction = {
 45→  type: "brain_action";
 46→  action: string;
 47→  resource: string;
 48→  constraints?: Record<string, unknown>;
 49→};
 50→
 51→export type IntentSubmissionResult = {
 52→  intentId: string;
 53→  status: string;
 54→};
 55→
 56→export type TokenResponse = {
 57→  access_token: string;
 58→  token_type: string;
 59→  expires_in: number;
 60→};
 61→
 62→export type TokenErrorResponse = {
 63→  error: string;
 64→  error_description?: string;
 65→};
 66→
 67→export type BridgeExchangeResult = {
 68→  access_token: string;
 69→  token_type: string;
 70→  expires_in: number;
 71→};
 72→
 73→export type OAuthTestRuntime = AcceptanceTestRuntime;
 74→
 75→export type TestUserWithSession = BaseTestUser & {
 76→  userId: string;
 77→};
 78→
 79→// ---------------------------------------------------------------------------
 80→// Suite Setup
 81→// ---------------------------------------------------------------------------
 82→
 83→/**
 84→ * Sets up an acceptance test suite with OAuth-specific configuration.
 85→ * Boots in-process server with isolated SurrealDB namespace.
 86→ */
 87→export function setupOAuthSuite(
 88→  suiteName: string,
 89→): () => OAuthTestRuntime {
 90→  return setupAcceptanceSuite(suiteName);
 91→}
 92→
 93→// ---------------------------------------------------------------------------
 94→// DPoP Key Pair Lifecycle Helpers
 95→// ---------------------------------------------------------------------------
 96→
 97→/**
 98→ * Generates an ES256 key pair for DPoP proof signing.
 99→ * Simulates what an agent sandbox or browser session does at startup.
100→ */
101→export async function generateActorKeyPair(): Promise<DPoPKeyPair> {
102→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
103→    { name: "ECDSA", namedCurve: "P-256" },
104→    true,
105→    ["sign", "verify"],
106→  );
107→
108→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
109→
110→  const thumbprint = await computeKeyThumbprint(publicJwk);
111→
112→  return { privateKey, publicKey, publicJwk, thumbprint };
113→}
114→
115→/**
116→ * Computes JWK thumbprint per RFC 7638.
117→ * The thumbprint uniquely identifies an actor's key for sender binding.
118→ */
119→export async function computeKeyThumbprint(publicJwk: JsonWebKey): Promise<string> {
120→  // RFC 7638: for EC keys, use only { crv, kty, x, y } in lexicographic order
121→  const thumbprintInput = JSON.stringify({
122→    crv: publicJwk.crv,
123→    kty: publicJwk.kty,
124→    x: publicJwk.x,
125→    y: publicJwk.y,
126→  });
127→
128→  const hashBuffer = await crypto.subtle.digest(
129→    "SHA-256",
130→    new TextEncoder().encode(thumbprintInput),
131→  );
132→
133→  return base64url(new Uint8Array(hashBuffer));
134→}
135→
136→// ---------------------------------------------------------------------------
137→// DPoP Proof Construction
138→// ---------------------------------------------------------------------------
139→
140→/**
141→ * Creates a signed DPoP proof for a specific request.
142→ * Each proof is bound to an HTTP method and target URI.
143→ */
144→export async function createProofForRequest(
145→  keyPair: DPoPKeyPair,
146→  method: string,
147→  targetUri: string,
148→): Promise<string> {
149→  const header = {
150→    typ: "dpop+jwt",
151→    alg: "ES256",
152→    jwk: {
153→      kty: keyPair.publicJwk.kty,
154→      crv: keyPair.publicJwk.crv,
155→      x: keyPair.publicJwk.x,
156→      y: keyPair.publicJwk.y,
157→    },
158→  };
159→
160→  const payload = {
161→    jti: crypto.randomUUID(),
162→    htm: method,
163→    htu: targetUri,
164→    iat: Math.floor(Date.now() / 1000),
165→  };
166→
167→  const importedKey = await jose.importJWK(
168→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
169→    "ES256",
170→  );
171→
172→  return await new jose.SignJWT(payload)
173→    .setProtectedHeader(header)
174→    .sign(importedKey);
175→}
176→
177→/**
178→ * Creates a DPoP proof with tampered claims for error path testing.
179→ */
180→export async function createMalformedProof(
181→  keyPair: DPoPKeyPair,
182→  overrides: {
183→    typ?: string;
184→    alg?: string;
185→    htm?: string;
186→    htu?: string;
187→    iat?: number;
188→    jti?: string;
189→    omitJwk?: boolean;
190→  },
191→): Promise<string> {
192→  const header: Record<string, unknown> = {
193→    typ: overrides.typ ?? "dpop+jwt",
194→    alg: overrides.alg ?? "ES256",
195→  };
196→
197→  if (!overrides.omitJwk) {
198→    header.jwk = {
199→      kty: keyPair.publicJwk.kty,
200→      crv: keyPair.publicJwk.crv,
201→      x: keyPair.publicJwk.x,
202→      y: keyPair.publicJwk.y,
203→    };
204→  }
205→
206→  const payload = {
207→    jti: overrides.jti ?? crypto.randomUUID(),
208→    htm: overrides.htm ?? "POST",
209→    htu: overrides.htu ?? "http://127.0.0.1/test",
210→    iat: overrides.iat ?? Math.floor(Date.now() / 1000),
211→  };
212→
213→  const importedKey = await jose.importJWK(
214→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
215→    "ES256",
216→  );
217→
218→  return await new jose.SignJWT(payload)
219→    .setProtectedHeader(header as jose.JWTHeaderParameters)
220→    .sign(importedKey);
221→}
222→
223→// ---------------------------------------------------------------------------
224→// Intent Submission (Driving Port: POST /api/auth/intents)
225→// ---------------------------------------------------------------------------
226→
227→/**
228→ * Submits an intent with DPoP thumbprint binding through the driving port.
229→ * This is how agents declare what they want to do.
230→ */
231→export async function submitIntentWithDPoP(
232→  baseUrl: string,
233→  workspaceId: string,
234→  identityId: string,
235→  brainAction: BrainAction,
236→  thumbprint: string,
237→  options?: {
238→    goal?: string;
239→    reasoning?: string;
240→    priority?: number;
241→  },
242→): Promise<Response> {
243→  return fetch(`${baseUrl}/api/auth/intents`, {
244→    method: "POST",
245→    headers: { "Content-Type": "application/json" },
246→    body: JSON.stringify({
247→      workspace_id: workspaceId,
248→      identity_id: identityId,
249→      authorization_details: [brainAction],
250→      dpop_jwk_thumbprint: thumbprint,
251→      goal: options?.goal ?? "Perform authorized operation",
252→      reasoning: options?.reasoning ?? "Operation required for task completion",
253→      priority: options?.priority ?? 50,
254→    }),
255→  });
256→}
257→
258→// ---------------------------------------------------------------------------
259→// Token Acquisition (Driving Port: POST /api/auth/token)
260→// ---------------------------------------------------------------------------
261→
262→/**
263→ * Requests a DPoP-bound access token from the Custom AS.
264→ * The agent presents proof of key possession along with an authorized intent.
265→ */
266→export async function requestAccessToken(
267→  baseUrl: string,
268→  intentId: string,
269→  keyPair: DPoPKeyPair,
270→  authorizationDetails: BrainAction[],
271→): Promise<Response> {
