 93→// ---------------------------------------------------------------------------
 94→// DPoP Key Pair Lifecycle Helpers
 95→// ---------------------------------------------------------------------------
 96→
 97→/**
 98→ * Generates an ES256 key pair for DPoP proof signing.
 99→ * Simulates what an agent sandbox or browser session does at startup.
100→ */
101→export async function generateActorKeyPair(): Promise<DPoPKeyPair> {
102→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
103→    { name: "ECDSA", namedCurve: "P-256" },
104→    true,
105→    ["sign", "verify"],
106→  );
107→
108→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
109→
110→  const thumbprint = await computeKeyThumbprint(publicJwk);
111→
112→  return { privateKey, publicKey, publicJwk, thumbprint };
113→}
114→
115→/**
116→ * Computes JWK thumbprint per RFC 7638.
117→ * The thumbprint uniquely identifies an actor's key for sender binding.
118→ */
119→export async function computeKeyThumbprint(publicJwk: JsonWebKey): Promise<string> {
120→  // RFC 7638: for EC keys, use only { crv, kty, x, y } in lexicographic order
121→  const thumbprintInput = JSON.stringify({
122→    crv: publicJwk.crv,
123→    kty: publicJwk.kty,
124→    x: publicJwk.x,
125→    y: publicJwk.y,
126→  });
127→
128→  const hashBuffer = await crypto.subtle.digest(
129→    "SHA-256",
130→    new TextEncoder().encode(thumbprintInput),
131→  );
132→
133→  return base64url(new Uint8Array(hashBuffer));
134→}
