623→/**
624→ * Waits for an intent to reach a target status by polling the database.
625→ */
626→export async function waitForIntentStatus(
627→  surreal: Surreal,
628→  intentId: string,
629→  targetStatuses: string[],
630→  timeoutMs = 30_000,
631→): Promise<string> {
632→  const intentRecord = new RecordId("intent", intentId);
633→  const start = Date.now();
634→
635→  while (Date.now() - start < timeoutMs) {
636→    const rows = (await surreal.query(`SELECT status FROM $intent;`, {
637→      intent: intentRecord,
638→    })) as Array<Array<{ status: string }>>;
639→
640→    const status = rows[0]?.[0]?.status;
641→    if (status && targetStatuses.includes(status)) {
642→      return status;
643→    }
644→
645→    await Bun.sleep(250);
646→  }
647→
648→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
649→    intent: intentRecord,
650→  })) as Array<Array<{ status: string }>>;
651→
652→  throw new Error(
653→    `Intent ${intentId} did not reach ${targetStatuses.join("|")} within ${timeoutMs}ms. ` +
654→    `Current status: ${rows[0]?.[0]?.status ?? "not found"}`,
655→  );
656→}
