136→// ---------------------------------------------------------------------------
137→// DPoP Proof Construction
138→// ---------------------------------------------------------------------------
139→
140→/**
141→ * Creates a signed DPoP proof for a specific request.
142→ * Each proof is bound to an HTTP method and target URI.
143→ */
144→export async function createProofForRequest(
145→  keyPair: DPoPKeyPair,
146→  method: string,
147→  targetUri: string,
148→): Promise<string> {
149→  const header = {
150→    typ: "dpop+jwt",
151→    alg: "ES256",
152→    jwk: {
153→      kty: keyPair.publicJwk.kty,
154→      crv: keyPair.publicJwk.crv,
155→      x: keyPair.publicJwk.x,
156→      y: keyPair.publicJwk.y,
157→    },
158→  };
159→
160→  const payload = {
161→    jti: crypto.randomUUID(),
162→    htm: method,
163→    htu: targetUri,
164→    iat: Math.floor(Date.now() / 1000),
165→  };
166→
167→  const importedKey = await jose.importJWK(
168→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
169→    "ES256",
170→  );
171→
172→  return await new jose.SignJWT(payload)
173→    .setProtectedHeader(header)
174→    .sign(importedKey);
175→}
176→
177→/**
178→ * Creates a DPoP proof with tampered claims for error path testing.
179→ */
180→export async function createMalformedProof(
181→  keyPair: DPoPKeyPair,
182→  overrides: {
183→    typ?: string;
184→    alg?: string;
185→    htm?: string;
186→    htu?: string;
187→    iat?: number;
188→    jti?: string;
189→    omitJwk?: boolean;
190→  },
191→): Promise<string> {
192→  const header: Record<string, unknown> = {
193→    typ: overrides.typ ?? "dpop+jwt",
194→    alg: overrides.alg ?? "ES256",
195→  };
196→
197→  if (!overrides.omitJwk) {
198→    header.jwk = {
199→      kty: keyPair.publicJwk.kty,
200→      crv: keyPair.publicJwk.crv,
201→      x: keyPair.publicJwk.x,
202→      y: keyPair.publicJwk.y,
203→    };
204→  }
205→
206→  const payload = {
207→    jti: overrides.jti ?? crypto.randomUUID(),
208→    htm: overrides.htm ?? "POST",
209→    htu: overrides.htu ?? "http://127.0.0.1/test",
210→    iat: overrides.iat ?? Math.floor(Date.now() / 1000),
211→  };
212→
213→  const importedKey = await jose.importJWK(
214→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
215→    "ES256",
216→  );
217→
218→  return await new jose.SignJWT(payload)
219→    .setProtectedHeader(header as jose.JWTHeaderParameters)
220→    .sign(importedKey);
221→}
