/**
 * Unit tests for OAuth RAR+DPoP algebraic data types.
 *
 * Tests type construction and validation helpers for domain types.
 */
import { describe, expect, it } from "bun:test";
import {
  type BrainAction,
  type DPoPErrorCode,
  type DPoPValidationResult,
  type TokenIssuanceResult,
  type RARVerificationResult,
  createBrainAction,
  DPOP_ERROR_CODES,
} from "../../../app/src/server/oauth/types";

describe("BrainAction construction", () => {
  it("creates a valid brain action with required fields", () => {
    const action = createBrainAction("read", "workspace");

    expect(action.type).toBe("brain_action");
    expect(action.action).toBe("read");
    expect(action.resource).toBe("workspace");
    expect(action.constraints).toBeUndefined();
  });

  it("creates a brain action with constraints", () => {
    const action = createBrainAction("update", "task", {
      task_id: "task-123",
    });

    expect(action.type).toBe("brain_action");
    expect(action.action).toBe("update");
    expect(action.resource).toBe("task");
    expect(action.constraints).toEqual({ task_id: "task-123" });
  });
});

describe("DPoPValidationResult discriminated union", () => {
  it("valid result carries thumbprint and claims", () => {
    const result: DPoPValidationResult = {
      valid: true,
      thumbprint: "abc123",
      claims: {
        jti: "unique-id",
        htm: "POST",
        htu: "https://example.com/api",
        iat: 1700000000,
      },
    };

    expect(result.valid).toBe(true);
    if (result.valid) {
      expect(result.thumbprint).toBe("abc123");
      expect(result.claims.htm).toBe("POST");
    }
  });

  it("invalid result carries error and code", () => {
    const result: DPoPValidationResult = {
      valid: false,
      error: "Missing DPoP proof",
      code: "dpop_required",
    };

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.error).toBe("Missing DPoP proof");
      expect(result.code).toBe("dpop_required");
    }
  });
});

describe("TokenIssuanceResult discriminated union", () => {
  it("ok result carries token and expiry", () => {
    const result: TokenIssuanceResult = {
      ok: true,
      token: "jwt-token-here",
      expiresAt: new Date("2026-01-01"),
    };

    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.token).toBe("jwt-token-here");
    }
  });

  it("error result carries error and code", () => {
    const result: TokenIssuanceResult = {
      ok: false,
      error: "Intent not authorized",
      code: "intent_not_authorized",
    };

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.code).toBe("intent_not_authorized");
    }
  });
});

describe("RARVerificationResult discriminated union", () => {
  it("authorized result", () => {
    const result: RARVerificationResult = { authorized: true };
    expect(result.authorized).toBe(true);
  });

  it("unauthorized result carries error and code", () => {
    const result: RARVerificationResult = {
      authorized: false,
      error: "Missing authorization_details",
      code: "authorization_details_missing",
    };

    expect(result.authorized).toBe(false);
    if (!result.authorized) {
      expect(result.code).toBe("authorization_details_missing");
    }
  });
});

describe("DPoP error codes", () => {
  it("all error codes are defined", () => {
    const expectedCodes: DPoPErrorCode[] = [
      "dpop_required",
      "dpop_invalid_structure",
      "dpop_invalid_signature",
      "dpop_proof_expired",
      "dpop_proof_reused",
      "dpop_binding_mismatch",
      "dpop_key_mismatch",
    ];

    for (const code of expectedCodes) {
      expect(DPOP_ERROR_CODES).toContain(code);
    }
  });
});

/**
 * Unit tests for DPoP pure functions.
 *
 * Tests:
 * - ES256 key pair generation
 * - JWK thumbprint computation (RFC 7638)
 * - DPoP proof validation (structure, signature, claims, clock skew)
 *
 * Acceptance criteria traced: M1-K1, M1-K2, M1-K3, M1-K4
 */
import { describe, expect, it } from "bun:test";
import * as jose from "jose";
import {
  generateKeyPair,
  computeJwkThumbprint,
  validateDPoPProof,
} from "../../../app/src/server/oauth/dpop";

// ---------------------------------------------------------------------------
// Helpers -- create signed DPoP proofs for testing validation
// ---------------------------------------------------------------------------

async function createSignedProof(
  keyPair: Awaited<ReturnType<typeof generateKeyPair>>,
  overrides?: {
    typ?: string;
    alg?: string;
    htm?: string;
    htu?: string;
    iat?: number;
    jti?: string;
    omitJwk?: boolean;
  },
): Promise<string> {
  const header: Record<string, unknown> = {
    typ: overrides?.typ ?? "dpop+jwt",
    alg: overrides?.alg ?? "ES256",
  };

  if (!overrides?.omitJwk) {
    header.jwk = {
      kty: keyPair.publicJwk.kty,
      crv: keyPair.publicJwk.crv,
      x: keyPair.publicJwk.x,
      y: keyPair.publicJwk.y,
    };
  }

  const payload = {
    jti: overrides?.jti ?? crypto.randomUUID(),
    htm: overrides?.htm ?? "POST",
    htu: overrides?.htu ?? "https://brain.example.com/api/auth/token",
    iat: overrides?.iat ?? Math.floor(Date.now() / 1000),
  };

  const importedKey = await jose.importJWK(
    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
    "ES256",
  );

  return await new jose.SignJWT(payload)
    .setProtectedHeader(header as jose.JWTHeaderParameters)
    .sign(importedKey);
}

// ===========================================================================
// M1-K1: ES256 key pair generation
// ===========================================================================

describe("generateKeyPair", () => {
  it("generates an ES256 key pair with EC P-256 public JWK", async () => {
    const keyPair = await generateKeyPair();

    expect(keyPair.publicJwk.kty).toBe("EC");
    expect(keyPair.publicJwk.crv).toBe("P-256");
    expect(keyPair.publicJwk.x).toBeTruthy();
    expect(keyPair.publicJwk.y).toBeTruthy();
    // Private key components should not leak into public JWK
    expect(keyPair.publicJwk.d).toBeUndefined();
  });

  it("includes a pre-computed thumbprint", async () => {
    const keyPair = await generateKeyPair();

    expect(keyPair.thumbprint).toBeTruthy();
    expect(keyPair.thumbprint.length).toBeGreaterThan(20);
  });

  it("produces keys usable for signing and verification", async () => {
    const keyPair = await generateKeyPair();

    // Sign some data
    const data = new TextEncoder().encode("test-payload");
    const signature = await crypto.subtle.sign(
      { name: "ECDSA", hash: "SHA-256" },
      keyPair.privateKey,
      data,
    );

    // Verify with public key
    const valid = await crypto.subtle.verify(
      { name: "ECDSA", hash: "SHA-256" },
      keyPair.publicKey,
      signature,
      data,
    );
    expect(valid).toBe(true);
  });
});

// ===========================================================================
// M1-K2: JWK thumbprint (RFC 7638)
// ===========================================================================

describe("computeJwkThumbprint", () => {
  it("is deterministic for the same key", async () => {
    const keyPair = await generateKeyPair();

    const thumbprint1 = await computeJwkThumbprint(keyPair.publicJwk);
    const thumbprint2 = await computeJwkThumbprint(keyPair.publicJwk);

    expect(thumbprint1).toBe(thumbprint2);
  });

  it("matches the pre-computed thumbprint from generateKeyPair", async () => {
    const keyPair = await generateKeyPair();

    const computed = await computeJwkThumbprint(keyPair.publicJwk);

    expect(computed).toBe(keyPair.thumbprint);
  });

  it("produces different thumbprints for different keys", async () => {
    const keyPair1 = await generateKeyPair();
    const keyPair2 = await generateKeyPair();

    expect(keyPair1.thumbprint).not.toBe(keyPair2.thumbprint);
  });

  it("matches thumbprint computed by the acceptance test kit algorithm", async () => {
    // Reproduce the test kit's base64url(SHA-256(JSON({crv,kty,x,y}))) algorithm
    const keyPair = await generateKeyPair();

    const thumbprintInput = JSON.stringify({
      crv: keyPair.publicJwk.crv,
      kty: keyPair.publicJwk.kty,
      x: keyPair.publicJwk.x,
      y: keyPair.publicJwk.y,
    });

    const hashBuffer = await crypto.subtle.digest(
      "SHA-256",
      new TextEncoder().encode(thumbprintInput),
    );

    const bytes = new Uint8Array(hashBuffer);
    const binary = String.fromCharCode(...bytes);
    const expected = btoa(binary)
      .replace(/\+/g, "-")
      .replace(/\//g, "_")
      .replace(/=/g, "");

    expect(keyPair.thumbprint).toBe(expected);
  });
});

// ===========================================================================
// M1-K3: DPoP proof structure validation
// ===========================================================================

describe("validateDPoPProof structure checks", () => {
  it("accepts a well-formed DPoP proof", async () => {
    const keyPair = await generateKeyPair();
    const proof = await createSignedProof(keyPair);

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(true);
    if (result.valid) {
      expect(result.thumbprint).toBe(keyPair.thumbprint);
      expect(result.claims.htm).toBe("POST");
      expect(result.claims.htu).toBe(
        "https://brain.example.com/api/auth/token",
      );
    }
  });

  it("rejects proof with wrong typ header", async () => {
    const keyPair = await generateKeyPair();
    const proof = await createSignedProof(keyPair, { typ: "JWT" });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_structure");
    }
  });

  it("rejects proof with missing jwk in header", async () => {
    const keyPair = await generateKeyPair();
    const proof = await createSignedProof(keyPair, { omitJwk: true });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_structure");
    }
  });

  it("rejects proof with mismatched HTTP method", async () => {
    const keyPair = await generateKeyPair();
    const proof = await createSignedProof(keyPair, { htm: "GET" });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_structure");
    }
  });

  it("rejects proof with mismatched target URI", async () => {
    const keyPair = await generateKeyPair();
    const proof = await createSignedProof(keyPair, {
      htu: "https://evil.example.com/steal",
    });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_structure");
    }
  });

  it("rejects non-JWT garbage input", async () => {
    const result = await validateDPoPProof(
      "not-a-jwt",
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_structure");
    }
  });
});

// ===========================================================================
// M1-K3: DPoP signature verification
// ===========================================================================

describe("validateDPoPProof signature verification", () => {
  it("rejects proof signed with a different key", async () => {
    const signingKeyPair = await generateKeyPair();
    const differentKeyPair = await generateKeyPair();

    // Create proof with signing key's private key but different key's public JWK in header
    const header = {
      typ: "dpop+jwt" as const,
      alg: "ES256" as const,
      jwk: {
        kty: differentKeyPair.publicJwk.kty,
        crv: differentKeyPair.publicJwk.crv,
        x: differentKeyPair.publicJwk.x,
        y: differentKeyPair.publicJwk.y,
      },
    };

    const payload = {
      jti: crypto.randomUUID(),
      htm: "POST",
      htu: "https://brain.example.com/api/auth/token",
      iat: Math.floor(Date.now() / 1000),
    };

    const importedKey = await jose.importJWK(
      await crypto.subtle.exportKey("jwk", signingKeyPair.privateKey),
      "ES256",
    );

    const proof = await new jose.SignJWT(payload)
      .setProtectedHeader(header)
      .sign(importedKey);

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_invalid_signature");
    }
  });
});

// ===========================================================================
// M1-K4: Clock skew tolerance
// ===========================================================================

describe("validateDPoPProof clock skew", () => {
  it("accepts proof within default 60s past tolerance", async () => {
    const keyPair = await generateKeyPair();
    const fiftySecondsAgo = Math.floor(Date.now() / 1000) - 50;
    const proof = await createSignedProof(keyPair, { iat: fiftySecondsAgo });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(true);
  });

  it("rejects proof older than 60s past tolerance", async () => {
    const keyPair = await generateKeyPair();
    const twoMinutesAgo = Math.floor(Date.now() / 1000) - 120;
    const proof = await createSignedProof(keyPair, { iat: twoMinutesAgo });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_proof_expired");
    }
  });

  it("accepts proof within default 5s future tolerance", async () => {
    const keyPair = await generateKeyPair();
    const threeSecondsAhead = Math.floor(Date.now() / 1000) + 3;
    const proof = await createSignedProof(keyPair, {
      iat: threeSecondsAhead,
    });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(true);
  });

  it("rejects proof too far in the future", async () => {
    const keyPair = await generateKeyPair();
    const tenSecondsAhead = Math.floor(Date.now() / 1000) + 10;
    const proof = await createSignedProof(keyPair, {
      iat: tenSecondsAhead,
    });

    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
    );

    expect(result.valid).toBe(false);
    if (!result.valid) {
      expect(result.code).toBe("dpop_proof_expired");
    }
  });

  it("respects custom clock skew configuration", async () => {
    const keyPair = await generateKeyPair();
    const ninetySecondsAgo = Math.floor(Date.now() / 1000) - 90;
    const proof = await createSignedProof(keyPair, { iat: ninetySecondsAgo });

    // With extended past tolerance of 120s, this should pass
    const result = await validateDPoPProof(
      proof,
      "POST",
      "https://brain.example.com/api/auth/token",
      { pastSeconds: 120, futureSeconds: 5 },
    );

    expect(result.valid).toBe(true);
  });
});

/**
 * OAuth RAR+DPoP Algebraic Data Types
 *
 * Types that make illegal states unrepresentable for the OAuth 2.1
 * RAR+DPoP sovereign authorization model.
 *
 * Pure domain types -- no IO imports.
 */
import type { RecordId } from "surrealdb";

// ---------------------------------------------------------------------------
// Brain Action (RFC 9396 Rich Authorization Request)
// ---------------------------------------------------------------------------

export type BrainAction = {
  type: "brain_action";
  action: string;
  resource: string;
  constraints?: Record<string, unknown>;
};

export function createBrainAction(
  action: string,
  resource: string,
  constraints?: Record<string, unknown>,
): BrainAction {
  return {
    type: "brain_action",
    action,
    resource,
    ...(constraints ? { constraints } : {}),
  };
}

// ---------------------------------------------------------------------------
// DPoP Proof Payload (claims inside a DPoP JWT)
// ---------------------------------------------------------------------------

export type DPoPProofPayload = {
  jti: string;
  htm: string;
  htu: string;
  iat: number;
};

// ---------------------------------------------------------------------------
// DPoP-Bound Token Claims (access token payload)
// ---------------------------------------------------------------------------

export type DPoPBoundTokenClaims = {
  sub: string;
  iss: string;
  aud: string;
  exp: number;
  iat: number;
  cnf: { jkt: string };
  authorization_details: BrainAction[];
  "urn:brain:intent_id": string;
  "urn:brain:workspace": string;
  "urn:brain:actor_type"?: string;
};

// ---------------------------------------------------------------------------
// DPoP Validation Result (discriminated union)
// ---------------------------------------------------------------------------

export type DPoPErrorCode =
  | "dpop_required"
  | "dpop_invalid_structure"
  | "dpop_invalid_signature"
  | "dpop_proof_expired"
  | "dpop_proof_reused"
  | "dpop_binding_mismatch"
  | "dpop_key_mismatch";

export const DPOP_ERROR_CODES: DPoPErrorCode[] = [
  "dpop_required",
  "dpop_invalid_structure",
  "dpop_invalid_signature",
  "dpop_proof_expired",
  "dpop_proof_reused",
  "dpop_binding_mismatch",
  "dpop_key_mismatch",
];

export type DPoPValidationResult =
  | { valid: true; thumbprint: string; claims: DPoPProofPayload }
  | { valid: false; error: string; code: DPoPErrorCode };

// ---------------------------------------------------------------------------
// Token Issuance Result (discriminated union)
// ---------------------------------------------------------------------------

export type TokenIssuanceResult =
  | { ok: true; token: string; expiresAt: Date }
  | { ok: false; error: string; code: string };

// ---------------------------------------------------------------------------
// RAR Verification Result (discriminated union)
// ---------------------------------------------------------------------------

export type RARErrorCode =
  | "authorization_details_missing"
  | "authorization_details_mismatch"
  | "authorization_params_exceeded";

export type RARVerificationResult =
  | { authorized: true }
  | { authorized: false; error: string; code: RARErrorCode };

// ---------------------------------------------------------------------------
// DPoP Auth Result (extracted from verified request)
// ---------------------------------------------------------------------------

export type DPoPAuthResult = {
  workspaceRecord: RecordId<"workspace", string>;
  workspaceName: string;
  identityRecord: RecordId<"identity", string>;
  actorType: "human" | "agent";
  authorizationDetails: BrainAction[];
  intentId: string;
  dpopThumbprint: string;
};

/**
 * DPoP Pure Functions
 *
 * Pure functions for DPoP proof validation, JWK thumbprint computation,
 * and ES256 key pair generation.
 *
 * No side effects -- all functions are pure (crypto operations are
 * deterministic given the same inputs).
 */
import * as jose from "jose";
import type { DPoPProofPayload, DPoPValidationResult } from "./types";

// ---------------------------------------------------------------------------
// Key Pair Generation (ES256 / ECDSA P-256)
// ---------------------------------------------------------------------------

export type KeyPair = {
  privateKey: CryptoKey;
  publicKey: CryptoKey;
  publicJwk: JsonWebKey;
  thumbprint: string;
};

/**
 * Generates an ES256 key pair with exportable keys and pre-computed thumbprint.
 * Used for testing and agent sandbox key provisioning.
 */
export async function generateKeyPair(): Promise<KeyPair> {
  const { publicKey, privateKey } = await crypto.subtle.generateKey(
    { name: "ECDSA", namedCurve: "P-256" },
    true,
    ["sign", "verify"],
  );

  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
  const thumbprint = await computeJwkThumbprint(publicJwk);

  return { privateKey, publicKey, publicJwk, thumbprint };
}

// ---------------------------------------------------------------------------
// JWK Thumbprint (RFC 7638)
// ---------------------------------------------------------------------------

/**
 * Computes a JWK thumbprint per RFC 7638.
 *
 * For EC keys: uses lexicographic order { crv, kty, x, y },
 * SHA-256 hash, base64url encoded.
 */
export async function computeJwkThumbprint(
  publicJwk: JsonWebKey,
): Promise<string> {
  const thumbprintInput = JSON.stringify({
    crv: publicJwk.crv,
    kty: publicJwk.kty,
    x: publicJwk.x,
    y: publicJwk.y,
  });

  const hashBuffer = await crypto.subtle.digest(
    "SHA-256",
    new TextEncoder().encode(thumbprintInput),
  );

  return base64url(new Uint8Array(hashBuffer));
}

// ---------------------------------------------------------------------------
// DPoP Proof Validation
// ---------------------------------------------------------------------------

type ClockSkew = {
  pastSeconds?: number;
  futureSeconds?: number;
};

const DEFAULT_CLOCK_SKEW: Required<ClockSkew> = {
  pastSeconds: 60,
  futureSeconds: 5,
};

/**
 * Validates a DPoP proof JWT.
 *
 * Checks:
 * 1. Structure: header typ="dpop+jwt", alg="ES256", jwk present with kty, crv, x, y
 * 2. Signature: verified against the embedded JWK
 * 3. Claims: jti present, htm matches expectedMethod, htu matches expectedUri
 * 4. Clock skew: iat within tolerance (default 60s past, 5s future)
 *
 * Returns the JWK thumbprint on success.
 */
export async function validateDPoPProof(
  proofJwt: string,
  expectedMethod: string,
  expectedUri: string,
  clockSkew?: ClockSkew,
): Promise<DPoPValidationResult> {
  const pastSeconds = clockSkew?.pastSeconds ?? DEFAULT_CLOCK_SKEW.pastSeconds;
  const futureSeconds =
    clockSkew?.futureSeconds ?? DEFAULT_CLOCK_SKEW.futureSeconds;

  // Step 1: Decode and validate structure (without verifying signature yet)
  const headerResult = decodeAndValidateHeader(proofJwt);
  if (!headerResult.ok) {
    return headerResult.error;
  }

  const { header, jwk } = headerResult.value;

  // Step 2: Verify signature against embedded JWK
  const verifyResult = await verifySignature(proofJwt, jwk);
  if (!verifyResult.ok) {
    return verifyResult.error;
  }

  const { payload } = verifyResult.value;

  // Step 3: Validate claims
  const claimsResult = validateClaims(
    payload,
    expectedMethod,
    expectedUri,
    pastSeconds,
    futureSeconds,
  );
  if (!claimsResult.ok) {
    return claimsResult.error;
  }

  // Step 4: Compute thumbprint from embedded JWK
  const thumbprint = await computeJwkThumbprint(jwk as JsonWebKey);

  return {
    valid: true,
    thumbprint,
    claims: claimsResult.value,
  };
}

// ---------------------------------------------------------------------------
// Internal validation pipeline steps
// ---------------------------------------------------------------------------

type ValidationOk<T> = { ok: true; value: T };
type ValidationErr = {
  ok: false;
  error: DPoPValidationResult & { valid: false };
};
type ValidationStep<T> = ValidationOk<T> | ValidationErr;

function decodeAndValidateHeader(
  proofJwt: string,
): ValidationStep<{ header: jose.ProtectedHeaderParameters; jwk: jose.JWK }> {
  try {
    const header = jose.decodeProtectedHeader(proofJwt);

    if (header.typ !== "dpop+jwt") {
      return invalidStructure("DPoP proof must have typ 'dpop+jwt'");
    }

    if (header.alg !== "ES256") {
      return invalidStructure("DPoP proof must use ES256 algorithm");
    }

    const jwk = header.jwk as jose.JWK | undefined;
    if (!jwk || !jwk.kty || !jwk.crv || !jwk.x || !jwk.y) {
      return invalidStructure(
        "DPoP proof must include jwk with kty, crv, x, y",
      );
    }

    return { ok: true, value: { header, jwk } };
  } catch {
    return invalidStructure("Failed to decode DPoP proof header");
  }
}

async function verifySignature(
  proofJwt: string,
  jwk: jose.JWK,
): Promise<ValidationStep<{ payload: jose.JWTPayload }>> {
  try {
    const publicKey = await jose.importJWK(jwk, "ES256");
    const { payload } = await jose.jwtVerify(proofJwt, publicKey);
    return { ok: true, value: { payload } };
  } catch {
    return {
      ok: false,
      error: {
        valid: false,
        error: "DPoP proof signature verification failed",
        code: "dpop_invalid_signature",
      },
    };
  }
}

function validateClaims(
  payload: jose.JWTPayload,
  expectedMethod: string,
  expectedUri: string,
  pastSeconds: number,
  futureSeconds: number,
): ValidationStep<DPoPProofPayload> {
  const jti = payload.jti as string | undefined;
  if (!jti) {
    return invalidStructure("DPoP proof must include jti claim");
  }

  const htm = payload.htm as string | undefined;
  if (htm !== expectedMethod) {
    return invalidStructure(
      `DPoP proof htm '${htm}' does not match expected '${expectedMethod}'`,
    );
  }

  const htu = payload.htu as string | undefined;
  if (htu !== expectedUri) {
    return invalidStructure(
      `DPoP proof htu '${htu}' does not match expected '${expectedUri}'`,
    );
  }

  const iat = payload.iat as number | undefined;
  if (iat === undefined) {
    return invalidStructure("DPoP proof must include iat claim");
  }

  const nowSeconds = Math.floor(Date.now() / 1000);
  if (iat < nowSeconds - pastSeconds) {
    return {
      ok: false,
      error: {
        valid: false,
        error: `DPoP proof too old: iat ${iat} is more than ${pastSeconds}s in the past`,
        code: "dpop_proof_expired",
      },
    };
  }

  if (iat > nowSeconds + futureSeconds) {
    return {
      ok: false,
      error: {
        valid: false,
        error: `DPoP proof too far in future: iat ${iat} is more than ${futureSeconds}s ahead`,
        code: "dpop_proof_expired",
      },
    };
  }

  return {
    ok: true,
    value: { jti, htm: htm!, htu: htu!, iat },
  };
}

// ---------------------------------------------------------------------------
// Utilities
// ---------------------------------------------------------------------------

function invalidStructure(message: string): ValidationErr {
  return {
    ok: false,
    error: {
      valid: false,
      error: message,
      code: "dpop_invalid_structure",
    },
  };
}

function base64url(bytes: Uint8Array): string {
  const binary = String.fromCharCode(...bytes);
  return btoa(binary)
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=/g, "");
}

