757→DEFINE FUNCTION fn::entity_edges($entity: record, $lim: int) {
758→  RETURN SELECT id, `in`, out, kind, confidence
759→    FROM entity_relation, belongs_to, has_feature, has_task, has_project,
760→         depends_on, owns, observes, suggests_for, subtask_of
761→    WHERE `in` = $entity OR out = $entity
