802→DEFINE FUNCTION fn::project_entity_ids($ws: record<workspace>, $project: record<project>) {
803→  LET $features = (SELECT VALUE out FROM has_feature WHERE `in` = $project);
804→  LET $tasks = (SELECT VALUE out FROM has_task WHERE `in` IN $features);
805→  LET $belongs_project = (SELECT VALUE `in` FROM belongs_to WHERE out = $project);
806→  LET $belongs_feature = (SELECT VALUE `in` FROM belongs_to WHERE out IN $features);
807→  LET $identities = (SELECT VALUE `in` FROM member_of WHERE out = $ws);
808→  LET $provenance = (
809→    SELECT VALUE out FROM extraction_relation
810→    WHERE `in` IN (
811→      SELECT VALUE id FROM message
812→      WHERE conversation IN (
813→        SELECT VALUE id FROM conversation WHERE workspace = $ws
814→      )
815→    )
816→  );
817→  RETURN array::distinct(
818→    [$project] + $features + $tasks +
819→    $belongs_project + $belongs_feature +
820→    $identities + $provenance
821→  );
822→};
