 6→export type InflightTracker = {
 7→  track(promise: Promise<unknown>): void;
 8→  drain(timeoutMs?: number): Promise<void>;
 9→};
10→
11→export function createInflightTracker(): InflightTracker {
12→  const pending = new Set<Promise<unknown>>();
13→  return {
14→    track(promise) {
15→      pending.add(promise);
16→      promise.finally(() => pending.delete(promise));
17→    },
18→    async drain(timeoutMs = 30_000) {
19→      if (pending.size === 0) return;
20→      await Promise.race([
21→        Promise.allSettled([...pending]),
22→        new Promise<void>((resolve) => setTimeout(resolve, timeoutMs)),
23→      ]);
24→    },
25→  };
26→}
