 21→// ---------------------------------------------------------------------------
 22→
 23→async function createSignedProof(
 24→  keyPair: Awaited<ReturnType<typeof generateKeyPair>>,
 25→  overrides?: {
 26→    typ?: string;
 27→    alg?: string;
 28→    htm?: string;
 29→    htu?: string;
 30→    iat?: number;
 31→    jti?: string;
 32→    omitJwk?: boolean;
 33→  },
 34→): Promise<string> {
 35→  const header: Record<string, unknown> = {
 36→    typ: overrides?.typ ?? "dpop+jwt",
 37→    alg: overrides?.alg ?? "ES256",
 38→  };
 39→
 40→  if (!overrides?.omitJwk) {
 41→    header.jwk = {
 42→      kty: keyPair.publicJwk.kty,
 43→      crv: keyPair.publicJwk.crv,
 44→      x: keyPair.publicJwk.x,
 45→      y: keyPair.publicJwk.y,
 46→    };
 47→  }
 48→
 49→  const payload = {
 50→    jti: overrides?.jti ?? crypto.randomUUID(),
 51→    htm: overrides?.htm ?? "POST",
 52→    htu: overrides?.htu ?? "https://brain.example.com/api/auth/token",
 53→    iat: overrides?.iat ?? Math.floor(Date.now() / 1000),
 54→  };
 55→
 56→  const importedKey = await jose.importJWK(
 57→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
 58→    "ES256",
 59→  );
 60→
 61→  return await new jose.SignJWT(payload)
 62→    .setProtectedHeader(header as jose.JWTHeaderParameters)
 63→    .sign(importedKey);
 64→}
