  1→/**
  2→ * AS Signing Key Management
  3→ *
  4→ * Generates, persists, and loads ES256 signing keys for the Authorization Server.
  5→ * Exposes JWKS response building for the /.well-known/jwks endpoint.
  6→ *
  7→ * Pure functions + thin DB adapters. Domain logic has no IO imports.
  8→ *
  9→ * Step: 02-01
 10→ */
 11→import { RecordId, type Surreal } from "surrealdb";
 12→import * as jose from "jose";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types
 16→// ---------------------------------------------------------------------------
 17→
 18→export type AsSigningKey = {
 19→  kid: string;
 20→  algorithm: "ES256";
 21→  publicJwk: JsonWebKey & { kid: string; alg: string; use: string };
 22→  privateKey: CryptoKey;
 23→};
 24→
 25→/** Row shape matching the as_signing_key SurrealDB table. */
 26→export type AsSigningKeyRow = {
 27→  kid: string;
 28→  algorithm: "ES256";
 29→  public_jwk: JsonWebKey;
 30→  private_jwk: JsonWebKey;
 31→  status: "active" | "rotated";
 32→  created_at: string;
 33→  rotated_at?: string;
 34→};
 35→
 36→// ---------------------------------------------------------------------------
 37→// Port signatures (driven ports)
 38→// ---------------------------------------------------------------------------
 39→
 40→type SaveKey = (row: AsSigningKeyRow) => Promise<void>;
 41→type LoadActiveKeyFromStore = () => Promise<AsSigningKeyRow | undefined>;
 42→
 43→// ---------------------------------------------------------------------------
 44→// Pure functions
 45→// ---------------------------------------------------------------------------
 46→
 47→/** Generate a new ES256 signing key with kid, exportable JWKs, and CryptoKey. */
 48→export async function generateAsSigningKey(): Promise<AsSigningKey> {
 49→  const kid = crypto.randomUUID();
 50→
 51→  const keyPair = await crypto.subtle.generateKey(
 52→    { name: "ECDSA", namedCurve: "P-256" },
 53→    true,
 54→    ["sign", "verify"],
 55→  );
 56→
 57→  const rawPublicJwk = await crypto.subtle.exportKey("jwk", keyPair.publicKey);
 58→
 59→  // Add JWKS metadata fields for RFC 7517 compliance
 60→  const publicJwk = {
 61→    ...rawPublicJwk,
 62→    kid,
 63→    alg: "ES256",
 64→    use: "sig",
 65→  } as AsSigningKey["publicJwk"];
 66→
 67→  // Remove private key material from public JWK
 68→  delete (publicJwk as Record<string, unknown>).d;
 69→
 70→  return {
 71→    kid,
 72→    algorithm: "ES256",
 73→    publicJwk,
 74→    privateKey: keyPair.privateKey,
 75→  };
 76→}
 77→
 78→/** Reconstruct an AsSigningKey from a stored DB row. */
 79→export async function loadActiveKey(row: AsSigningKeyRow): Promise<AsSigningKey> {
 80→  const privateKey = await crypto.subtle.importKey(
 81→    "jwk",
 82→    row.private_jwk,
 83→    { name: "ECDSA", namedCurve: "P-256" },
 84→    false,
 85→    ["sign"],
 86→  );
 87→
 88→  const publicJwk = {
 89→    ...row.public_jwk,
 90→    kid: row.kid,
 91→    alg: "ES256",
 92→    use: "sig",
 93→  } as AsSigningKey["publicJwk"];
 94→
 95→  // Ensure no private material in public JWK
 96→  delete (publicJwk as Record<string, unknown>).d;
 97→
 98→  return {
 99→    kid: row.kid,
100→    algorithm: "ES256",
101→    publicJwk,
102→    privateKey,
103→  };
104→}
105→
106→/** Build RFC 7517 JWK Set response for the JWKS endpoint. */
107→export function buildJwksResponse(key: AsSigningKey): jose.JSONWebKeySet {
108→  const jwk = { ...key.publicJwk };
109→  // Defensive: strip private material
110→  delete (jwk as Record<string, unknown>).d;
111→
112→  return {
113→    keys: [jwk as jose.JWK],
114→  };
115→}
