135→    kid: key.kid,
136→    algorithm: "ES256",
137→    public_jwk: key.publicJwk,
138→    private_jwk: privateJwk as JsonWebKey,
139→    status: "active",
140→    created_at: new Date().toISOString(),
141→  };
142→
