15→export function withRequestIdHeader(response: Response, requestId: string): Response {
16→  const headers = new Headers(response.headers);
17→  headers.set("x-request-id", requestId);
18→
19→  return new Response(response.body, {
20→    status: response.status,
21→    statusText: response.statusText,
22→    headers,
23→  });
24→}
