26→export function toIsoString(value: Date | string): string {
27→  if (value instanceof Date) {
28→    return value.toISOString();
29→  }
30→
31→  const parsed = new Date(value);
32→  if (!Number.isNaN(parsed.valueOf())) {
33→    return parsed.toISOString();
34→  }
35→
36→  return value;
37→}
