  1→/**
  2→ * OAuth RAR+DPoP Algebraic Data Types
  3→ *
  4→ * Types that make illegal states unrepresentable for the OAuth 2.1
  5→ * RAR+DPoP sovereign authorization model.
  6→ *
  7→ * Pure domain types -- no IO imports.
  8→ */
  9→import type { RecordId } from "surrealdb";
 10→
 11→// ---------------------------------------------------------------------------
 12→// Brain Action (RFC 9396 Rich Authorization Request)
 13→// ---------------------------------------------------------------------------
 14→
 15→export type BrainAction = {
 16→  type: "brain_action";
 17→  action: string;
 18→  resource: string;
 19→  constraints?: Record<string, unknown>;
 20→};
 21→
 22→export function createBrainAction(
 23→  action: string,
 24→  resource: string,
 25→  constraints?: Record<string, unknown>,
 26→): BrainAction {
 27→  return {
 28→    type: "brain_action",
 29→    action,
 30→    resource,
 31→    ...(constraints ? { constraints } : {}),
 32→  };
 33→}
 34→
 35→// ---------------------------------------------------------------------------
 36→// DPoP Proof Payload (claims inside a DPoP JWT)
 37→// ---------------------------------------------------------------------------
 38→
 39→export type DPoPProofPayload = {
 40→  jti: string;
 41→  htm: string;
 42→  htu: string;
 43→  iat: number;
 44→};
 45→
 46→// ---------------------------------------------------------------------------
 47→// DPoP-Bound Token Claims (access token payload)
 48→// ---------------------------------------------------------------------------
 49→
 50→export type DPoPBoundTokenClaims = {
 51→  sub: string;
 52→  iss: string;
 53→  aud: string;
 54→  exp: number;
 55→  iat: number;
 56→  cnf: { jkt: string };
 57→  authorization_details: BrainAction[];
 58→  "urn:brain:intent_id": string;
 59→  "urn:brain:workspace": string;
 60→  "urn:brain:actor_type"?: string;
 61→};
 62→
 63→// ---------------------------------------------------------------------------
 64→// DPoP Validation Result (discriminated union)
 65→// ---------------------------------------------------------------------------
 66→
 67→export type DPoPErrorCode =
 68→  | "dpop_required"
 69→  | "dpop_invalid_structure"
 70→  | "dpop_invalid_signature"
 71→  | "dpop_proof_expired"
 72→  | "dpop_proof_reused"
 73→  | "dpop_binding_mismatch"
 74→  | "dpop_key_mismatch";
 75→
 76→export const DPOP_ERROR_CODES: DPoPErrorCode[] = [
 77→  "dpop_required",
 78→  "dpop_invalid_structure",
 79→  "dpop_invalid_signature",
 80→  "dpop_proof_expired",
 81→  "dpop_proof_reused",
 82→  "dpop_binding_mismatch",
 83→  "dpop_key_mismatch",
 84→];
 85→
 86→export type DPoPValidationResult =
 87→  | { valid: true; thumbprint: string; claims: DPoPProofPayload }
 88→  | { valid: false; error: string; code: DPoPErrorCode };
 89→
 90→// ---------------------------------------------------------------------------
 91→// Token Issuance Result (discriminated union)
 92→// ---------------------------------------------------------------------------
 93→
 94→export type TokenIssuanceResult =
 95→  | { ok: true; token: string; expiresAt: Date }
 96→  | { ok: false; error: string; code: string };
 97→
 98→// ---------------------------------------------------------------------------
 99→// RAR Verification Result (discriminated union)
100→// ---------------------------------------------------------------------------
101→
102→export type RARErrorCode =
103→  | "authorization_details_missing"
104→  | "authorization_details_mismatch"
105→  | "authorization_params_exceeded";
106→
107→export type RARVerificationResult =
108→  | { authorized: true }
109→  | { authorized: false; error: string; code: RARErrorCode };
110→
111→// ---------------------------------------------------------------------------
112→// DPoP Auth Result (extracted from verified request)
113→// ---------------------------------------------------------------------------
114→
115→export type DPoPAuthResult = {
116→  workspaceRecord: RecordId<"workspace", string>;
117→  workspaceName: string;
118→  identityRecord: RecordId<"identity", string>;
119→  actorType: "human" | "agent";
120→  authorizationDetails: BrainAction[];
121→  intentId: string;
122→  dpopThumbprint: string;
123→};
