 4→-- Extends identity table with managed_by, identity_status, revoked_at.
 5→
 6→-- Intent table extensions: RAR authorization details
 7→DEFINE FIELD OVERWRITE authorization_details ON intent TYPE option<array<object>>;
 8→DEFINE FIELD OVERWRITE authorization_details[*].type ON intent TYPE string ASSERT $value = "brain_action";
 9→DEFINE FIELD OVERWRITE authorization_details[*].action ON intent TYPE string;
10→DEFINE FIELD OVERWRITE authorization_details[*].resource ON intent TYPE string;
11→DEFINE FIELD OVERWRITE authorization_details[*].constraints ON intent TYPE option<object> FLEXIBLE;
12→
13→-- Intent table extensions: DPoP binding and token lifecycle
14→DEFINE FIELD OVERWRITE dpop_jwk_thumbprint ON intent TYPE option<string>;
15→DEFINE FIELD OVERWRITE token_issued_at ON intent TYPE option<datetime>;
16→DEFINE FIELD OVERWRITE token_expires_at ON intent TYPE option<datetime>;
17→
18→-- Identity table extensions: managed identity support
19→DEFINE FIELD OVERWRITE managed_by ON identity TYPE option<string>;
20→DEFINE FIELD OVERWRITE identity_status ON identity TYPE option<string>;
21→DEFINE FIELD OVERWRITE revoked_at ON identity TYPE option<datetime>;
22→
23→-- Audit event table
24→DEFINE TABLE OVERWRITE audit_event SCHEMAFULL;
25→DEFINE FIELD OVERWRITE event_type ON audit_event TYPE string
26→  ASSERT $value IN ["intent_submitted", "intent_evaluated", "intent_routed", "consent_approved", "consent_constrained", "consent_vetoed", "token_issued", "token_rejected", "dpop_verified", "dpop_rejected", "security_alert"];
27→DEFINE FIELD OVERWRITE severity ON audit_event TYPE string
28→  ASSERT $value IN ["info", "warning", "security"];
29→DEFINE FIELD OVERWRITE actor ON audit_event TYPE record<identity>;
30→DEFINE FIELD OVERWRITE workspace ON audit_event TYPE record<workspace>;
31→DEFINE FIELD OVERWRITE intent_id ON audit_event TYPE option<record<intent>>;
32→DEFINE FIELD OVERWRITE dpop_thumbprint ON audit_event TYPE option<string>;
33→DEFINE FIELD OVERWRITE payload ON audit_event TYPE object FLEXIBLE;
34→DEFINE FIELD OVERWRITE created_at ON audit_event TYPE datetime;
35→DEFINE INDEX OVERWRITE audit_event_workspace_type ON audit_event FIELDS workspace, event_type;
36→DEFINE INDEX OVERWRITE audit_event_created_at ON audit_event FIELDS created_at;
37→DEFINE INDEX OVERWRITE audit_event_intent ON audit_event FIELDS intent_id;
38→DEFINE INDEX OVERWRITE audit_event_severity ON audit_event FIELDS severity;
39→
40→-- Authorization server signing key table
41→DEFINE TABLE OVERWRITE as_signing_key SCHEMAFULL;
42→DEFINE FIELD OVERWRITE kid ON as_signing_key TYPE string;
43→DEFINE FIELD OVERWRITE algorithm ON as_signing_key TYPE string ASSERT $value = "ES256";
44→DEFINE FIELD OVERWRITE public_jwk ON as_signing_key TYPE object FLEXIBLE;
45→DEFINE FIELD OVERWRITE private_jwk ON as_signing_key TYPE object FLEXIBLE;
46→DEFINE FIELD OVERWRITE status ON as_signing_key TYPE string
47→  ASSERT $value IN ["active", "rotated"];
