49→DEFINE FIELD OVERWRITE rotated_at ON as_signing_key TYPE option<datetime>;
50→DEFINE INDEX OVERWRITE as_signing_key_kid ON as_signing_key FIELDS kid UNIQUE;
51→DEFINE INDEX OVERWRITE as_signing_key_status ON as_signing_key FIELDS status;
